// 스케줄(08:00) → 전일 확정, 웹훅 → body.mode/targetDate 참조
let body = {};
try { body = $('수동 조회').first().json.body || {}; } catch(e) {}
const chatId = String(body.chatId || body.chat_id || '7713811206');
const requestedDate = String(body.targetDate || body.target_date || '').trim();
const mode = (body.mode || (requestedDate ? 'target-date' : 'yesterday')).toLowerCase();

const now = new Date();
const kstOffset = 9 * 60 * 60 * 1000;
const kstNow = new Date(now.getTime() + kstOffset);

const toDateString = (date) => date.toISOString().slice(0, 10);
const buildLabel = (date) => {
  const m = date.getMonth() + 1;
  const d = date.getDate();
  const dow = ['일','월','화','수','목','금','토'][date.getDay()];
  return `${m}/${d}(${dow}) 확정`;
};

let targetDate, label;
if (/^\d{4}-\d{2}-\d{2}$/.test(requestedDate)) {
  targetDate = requestedDate;
  const [y, m, d] = requestedDate.split('-').map(Number);
  const target = new Date(Date.UTC(y, m - 1, d));
  label = buildLabel(target);
} else if (mode === 'today') {
  targetDate = toDateString(kstNow);
  const h = parseInt(kstNow.toISOString().slice(11, 13));
  const min = kstNow.toISOString().slice(14, 16);
  label = `${kstNow.getMonth()+1}/${kstNow.getDate()} ${h}:${min} 기준 (집계 중)`;
} else {
  const yesterday = new Date(kstNow);
  yesterday.setDate(yesterday.getDate() - 1);
  targetDate = toDateString(yesterday);
  label = buildLabel(yesterday);
}

const fromDate = targetDate + ' 00:00:00';
const toDate = targetDate + ' 23:59:59';
const st11Date = targetDate.replace(/-/g, '');

// Google Sheets 일별 매출 행 번호 (A1=헤더, 1/1=2행)
const p = targetDate.split('-').map(Number);
const target = new Date(Date.UTC(p[0], p[1]-1, p[2]));
const jan1 = new Date(Date.UTC(p[0], 0, 1));
const sheetsRow = Math.round((target - jan1) / 86400000) + 2;

// 이번 달 누계용 (월 시작~전일)
const monthStart = targetDate.slice(0, 7) + '-01 00:00:00';

return [{ json: { chatId, mode, requestedDate, targetDate, fromDate, toDate, st11Date, monthStart, label, sheetsRow } }];

// 네이버 커머스 API: bcrypt 서명 + httpRequest로 토큰 발급
const bcrypt = require('bcryptjs');
const clientId = $env.NAVER_COMMERCE_CLIENT_ID || '';
const clientSecret = $env.NAVER_COMMERCE_CLIENT_SECRET || '';

if (!clientId || !clientSecret) {
  return [{ json: { error: 'NAVER_COMMERCE 환경변수 미설정', accessToken: '' } }];
}

try {
  const timestamp = Date.now();
  const password = clientId + '_' + timestamp;
  const hashed = bcrypt.hashSync(password, clientSecret);
  const signature = Buffer.from(hashed).toString('base64');

  const tokenData = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.commerce.naver.com/external/v1/oauth2/token',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    body: 'client_id=' + encodeURIComponent(clientId) + '&timestamp=' + timestamp + '&client_secret_sign=' + encodeURIComponent(signature) + '&grant_type=client_credentials&type=SELF'
  });

  if (!tokenData.access_token) {
    return [{ json: { error: 'Token: ' + JSON.stringify(tokenData).slice(0, 200), accessToken: '' } }];
  }
  return [{ json: { accessToken: tokenData.access_token, error: '' } }];
} catch (e) {
  const respBody = e.response && e.response.data ? JSON.stringify(e.response.data).slice(0, 200) : '';
  return [{ json: { error: 'Naver auth ' + e.message + (respBody ? ' | ' + respBody : ''), accessToken: '' } }];
}

// 네이버 커머스 주문 조회 (GET product-orders)
const token = $('네이버 인증').first().json.accessToken || '';
const dateInfo = $('날짜 계산').first().json;

if (!token) {
  return [{ json: { error: $('네이버 인증').first().json.error || 'No token', totalRevenue: 0, totalOrders: 0 } }];
}

try {
  const from = dateInfo.targetDate + 'T00:00:00.000%2B09:00';
  const to = dateInfo.targetDate + 'T23:59:59.999%2B09:00';

  const data = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://api.commerce.naver.com/external/v1/pay-order/seller/product-orders?from=' + from + '&to=' + to,
    headers: { 'Authorization': 'Bearer ' + token }
  });

  const contents = (data.data && data.data.contents) || [];
  const CANCEL = ['CANCELED', 'RETURNED', 'EXCHANGED', 'CANCEL_REQUEST', 'RETURN_REQUEST', 'CANCEL_DONE'];
  let totalRevenue = 0, totalOrders = 0, cancelCount = 0;

  for (const item of contents) {
    const po = item.content && item.content.productOrder;
    if (!po) continue;
    const status = po.productOrderStatus || '';
    if (CANCEL.includes(status)) { cancelCount++; continue; }
    totalRevenue += parseInt(po.totalPaymentAmount || 0);
    totalOrders++;
  }

  return [{ json: { totalRevenue, totalOrders, cancelCount, rawCount: contents.length, error: '' } }];
} catch (e) {
  return [{ json: { error: 'Naver orders: ' + e.message, totalRevenue: 0, totalOrders: 0 } }];
}

// 11번가 Seller API: 주문 상태별 복수 endpoint 조회
// /complete만 보면 이미 배송/판매완료로 넘어간 주문을 놓친다.
// targetDate의 주문일(ordDt) 기준으로 complete/packaging/shipping/dlvcompleted/completed를 합산한다.
const apiKey = $env.ST11_API_KEY || '';
const dateInfo = $('날짜 계산').first().json;

if (!apiKey) {
  return [{ json: { error: 'ST11_API_KEY 미설정', totalRevenue: 0, totalOrders: 0, rawCount: 0, source: 'st11_multi_status' } }];
}

const num = (v) => {
  if (v === undefined || v === null || v === '') return 0;
  const s = String(v).replace(/[^0-9.-]/g, '');
  return parseInt(s) || 0;
};
const get = (chunk, f) => {
  const re = new RegExp('<(?:ns2:)?' + f + '>([\\s\\S]*?)</(?:ns2:)?' + f + '>', 'i');
  const m = chunk.match(re);
  return m ? String(m[1] || '').replace(/<!\[CDATA\[|\]\]>/g, '').trim() : '';
};
const date10 = (v) => {
  const s = String(v || '');
  if (/^\d{4}-\d{2}-\d{2}/.test(s)) return s.slice(0, 10);
  if (/^\d{4}\d{2}\d{2}/.test(s)) return s.slice(0, 4) + '-' + s.slice(4, 6) + '-' + s.slice(6, 8);
  return '';
};
const pickAmount = (chunk) => {
  // ordAmt가 상품 매출 기준에 가장 잘 맞음. 없으면 결제/상품금액으로 보완.
  return num(get(chunk, 'ordAmt')) || num(get(chunk, 'ordPayAmt')) || num(get(chunk, 'prdPayAmt')) || num(get(chunk, 'selPrc'));
};

const d = dateInfo.st11Date; // yyyyMMdd
const startDateTime = d + '0000';
const endDateTime = d + '2359';
const endpoints = [
  'complete',
  'packaging',
  'shipping',
  'dlvcompleted',
  'completed',
  'reservatecomplete',
];

const seen = new Set();
const rows = [];
const errors = [];

for (const ep of endpoints) {
  try {
    const xml = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://api.11st.co.kr/rest/ordservices/' + ep + '/' + startDateTime + '/' + endDateTime,
      headers: { openapikey: apiKey },
      returnFullResponse: false,
      encoding: 'utf-8',
      timeout: 20000,
    });
    const xmlStr = typeof xml === 'string' ? xml : JSON.stringify(xml);
    if (xmlStr.includes('조회된 결과가 없습니다') || xmlStr.includes('해당 건이 없습니다')) continue;
    const orderMatches = xmlStr.match(/<(?:ns2:)?order>[\s\S]*?<\/(?:ns2:)?order>/g) || [];
    for (const chunk of orderMatches) {
      const ordDate = date10(get(chunk, 'ordDt'));
      if (ordDate !== dateInfo.targetDate) continue;
      const ordNo = get(chunk, 'ordNo');
      const seq = get(chunk, 'ordPrdSeq');
      const key = ordNo + '_' + seq;
      if (seen.has(key)) continue;
      const amount = pickAmount(chunk);
      if (amount <= 0) continue;
      seen.add(key);
      rows.push({ endpoint: ep, ordNo, seq, amount, ordDate });
    }
  } catch (e) {
    errors.push(ep + ': ' + e.message);
  }
}

const totalRevenue = rows.reduce((sum, r) => sum + r.amount, 0);
return [{ json: { totalRevenue, totalOrders: seen.size, rawCount: rows.length, rows, error: errors.join(' | '), source: 'st11_multi_status' } }];

// 쿠팡윙 OpenAPI 주문 조회
// 운영 정책:
// - 매일 14:30~19:00(KST)는 사방넷 출고 연동 시간으로 쿠팡 매출 API 사용 금지
// - 금지 시간에는 API를 호출하지 않고, 뒤쪽 집계 노드가 기존 NocoDB/구글시트 값을 유지한다.
// - 쿠팡은 간헐 403/429가 발생하므로 상태별 호출 사이를 늦추고, 재시도/페이지네이션을 적용한다.
const crypto = require('crypto');
const dateInfo = $('날짜 계산').first().json;

const kstNow = new Date(Date.now() + 9 * 60 * 60 * 1000);
const kstIso = kstNow.toISOString();
const kstDate = kstIso.slice(0, 10);
const kstHour = parseInt(kstIso.slice(11, 13));
const kstMinute = parseInt(kstIso.slice(14, 16));
const nowMinutes = kstHour * 60 + kstMinute;
const isCoupangBlackout = nowMinutes >= (14 * 60 + 30) && nowMinutes < (19 * 60);

if (isCoupangBlackout) {
  const reason = '14:30~19:00 사방넷 출고 연동 시간';
  return [{ json: {
    skipped: true,
    reason,
    blackoutWindow: 'KST 14:30-19:00',
    kstNow: kstDate + ' ' + String(kstHour).padStart(2, '0') + ':' + String(kstMinute).padStart(2, '0'),
    totalRevenue: 0,
    totalOrders: 0,
    rawCount: 0,
    error: '',
    source: 'coupang_wing_openapi_skipped',
  } }];
}

const accessKey = $env.COUPANG_ACCESS_KEY || $env.COUPANG_API_ACCESS_KEY || '';
const secretKey = $env.COUPANG_SECRET_KEY || $env.COUPANG_API_SECRET_KEY || '';
const vendorId = $env.COUPANG_VENDOR_ID || $env.COUPANG_API_VENDOR_ID || '';
const baseUrl = $env.COUPANG_API_BASE_URL || 'https://api-gateway.coupang.com';

if (!accessKey || !secretKey || !vendorId) {
  return [{ json: {
    skipped: true,
    reason: 'COUPANG 환경변수 미설정 — 기존 구글시트 G열 값 유지',
    totalRevenue: 0,
    totalOrders: 0,
    rawCount: 0,
    error: 'COUPANG_ACCESS_KEY / COUPANG_SECRET_KEY / COUPANG_VENDOR_ID 미설정',
    source: 'coupang_wing_openapi_skipped_missing_env',
  } }];
}

const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));
const signedDate = () => {
  const iso = new Date().toISOString();
  return iso.slice(2, 4) + iso.slice(5, 7) + iso.slice(8, 10) + 'T' + iso.slice(11, 13) + iso.slice(14, 16) + iso.slice(17, 19) + 'Z';
};

const makeAuthHeader = (method, path, query) => {
  const ts = signedDate();
  const message = ts + method + path + query;
  const signature = crypto.createHmac('sha256', secretKey).update(message).digest('hex');
  return 'CEA algorithm=HmacSHA256, access-key=' + accessKey + ', signed-date=' + ts + ', signature=' + signature;
};

const enc = (v) => encodeURIComponent(String(v));
const queryString = (obj) => Object.keys(obj)
  .filter((k) => obj[k] !== undefined && obj[k] !== null && obj[k] !== '')
  .map((k) => enc(k) + '=' + enc(obj[k]))
  .join('&');

const money = (v) => {
  if (v === undefined || v === null || v === '') return 0;
  if (typeof v === 'number') return Math.round(v);
  if (typeof v === 'string') return parseInt(v.replace(/[^0-9.-]/g, '')) || 0;
  if (typeof v === 'object') {
    const units = parseInt(v.units || v.amount || v.value || 0) || 0;
    const nanos = parseInt(v.nanos || 0) || 0;
    return units + Math.round(nanos / 1000000000);
  }
  return 0;
};

const summarizeError = (e) => {
  const parts = [];
  const statusCode = e && (e.statusCode || e.httpCode || (e.response && (e.response.statusCode || e.response.status)));
  if (statusCode) parts.push('HTTP ' + statusCode);
  const body = e && e.response && (e.response.body || e.response.data);
  if (body) {
    if (typeof body === 'string') {
      try {
        const parsed = JSON.parse(body);
        if (parsed.code) parts.push('code=' + parsed.code);
        if (parsed.message) parts.push(String(parsed.message).slice(0, 120));
      } catch (parseError) {
        parts.push(body.slice(0, 120));
      }
    } else if (typeof body === 'object') {
      if (body.code) parts.push('code=' + body.code);
      if (body.message) parts.push(String(body.message).slice(0, 120));
    }
  }
  if (e && e.message) parts.push(String(e.message).slice(0, 120));
  return parts.filter(Boolean).join(' / ') || 'unknown error';
};

const isRetryableError = (e) => {
  const statusCode = e && (e.statusCode || e.httpCode || (e.response && (e.response.statusCode || e.response.status)));
  if ([403, 408, 409, 425, 429, 500, 502, 503, 504].includes(Number(statusCode))) return true;
  const msg = String((e && e.message) || '').toLowerCase();
  return msg.includes('timeout') || msg.includes('econnreset') || msg.includes('socket hang up');
};

const path = '/v2/providers/openapi/apis/api/v5/vendors/' + encodeURIComponent(vendorId) + '/ordersheets';
const from = dateInfo.targetDate + 'T00:00+09:00';
const to = dateInfo.targetDate + 'T23:59+09:00';
const statuses = ['ACCEPT', 'INSTRUCT', 'DEPARTURE', 'DELIVERING', 'FINAL_DELIVERY', 'NONE_TRACKING'];
const statusDelayMs = 1200;
const pageDelayMs = 450;
const maxAttempts = 3;
const maxPagesPerStatus = 20;

const requestPage = async (query, status) => {
  let lastError = null;
  for (let attempt = 1; attempt <= maxAttempts; attempt++) {
    try {
      const auth = makeAuthHeader('GET', path, query);
      let resp = await this.helpers.httpRequest({
        method: 'GET',
        url: baseUrl + path + '?' + query,
        headers: {
          Authorization: auth,
          'Content-Type': 'application/json;charset=UTF-8',
        },
        timeout: 30000,
      });
      if (typeof resp === 'string') {
        try { resp = JSON.parse(resp); } catch(e) { resp = { raw: resp }; }
      }
      if (resp && resp.code && String(resp.code) !== '200' && String(resp.code).toUpperCase() !== 'SUCCESS') {
        throw new Error('Coupang body error ' + (resp.message || resp.code));
      }
      return { resp, attempts: attempt };
    } catch (e) {
      lastError = e;
      if (attempt >= maxAttempts || !isRetryableError(e)) break;
      await sleep(statusDelayMs * attempt);
    }
  }
  throw new Error(status + ': ' + summarizeError(lastError));
};

let totalRevenue = 0;
const orderIds = new Set();
const lineKeys = new Set();
const apiErrors = [];
const statusSummary = [];
let rawCount = 0;
let retryCount = 0;

for (const status of statuses) {
  let nextToken = '';
  let pages = 0;
  let statusRows = 0;
  let statusAmount = 0;
  let statusRetries = 0;

  try {
    while (pages < maxPagesPerStatus) {
      pages++;
      const query = queryString({
        createdAtFrom: from,
        createdAtTo: to,
        searchType: 'timeFrame',
        status,
        nextToken,
      });
      const pageResult = await requestPage(query, status);
      const resp = pageResult.resp;
      const attempts = pageResult.attempts || 1;
      if (attempts > 1) {
        statusRetries += attempts - 1;
        retryCount += attempts - 1;
      }

      const rows = Array.isArray(resp && resp.data) ? resp.data : [];
      rawCount += rows.length;
      statusRows += rows.length;

      for (const order of rows) {
        const orderId = String(order.orderId || order.shipmentBoxId || '');
        if (orderId) orderIds.add(orderId);
        const items = Array.isArray(order.orderItems) ? order.orderItems : [];
        for (const item of items) {
          if (item.canceled === true) continue;
          const shippingCount = parseInt(item.shippingCount || item.salesQuantity || 1) || 1;
          const cancelCount = parseInt(item.cancelCount || 0) || 0;
          const holdCount = parseInt(item.holdCountForCancel || 0) || 0;
          const activeCount = Math.max(0, shippingCount - cancelCount - holdCount);
          if (activeCount <= 0) continue;

          const key = [orderId, order.shipmentBoxId || '', item.vendorItemId || '', item.sellerProductId || '', item.vendorItemName || item.productName || ''].join(':');
          if (lineKeys.has(key)) continue;
          lineKeys.add(key);

          let lineAmount = money(item.orderPrice);
          if (lineAmount <= 0) {
            const unit = money(item.salesPrice || item.unitSalesPrice);
            lineAmount = unit * activeCount;
          } else if (activeCount !== shippingCount && shippingCount > 0) {
            lineAmount = Math.round(lineAmount * activeCount / shippingCount);
          }
          totalRevenue += lineAmount;
          statusAmount += lineAmount;
        }
      }

      nextToken = resp && resp.nextToken ? String(resp.nextToken) : '';
      if (!nextToken) break;
      await sleep(pageDelayMs);
    }

    if (nextToken) {
      apiErrors.push(status + ': page limit exceeded with nextToken remaining');
    }
    statusSummary.push({ status, rows: statusRows, pages, amount: statusAmount, retries: statusRetries, truncated: !!nextToken });
  } catch (e) {
    apiErrors.push(e.message || String(e));
    statusSummary.push({ status, rows: statusRows, pages, amount: statusAmount, retries: statusRetries, error: (e.message || String(e)).slice(0, 160) });
  }

  await sleep(statusDelayMs);
}

return [{ json: {
  skipped: false,
  totalRevenue,
  totalOrders: orderIds.size,
  rawCount,
  lineCount: lineKeys.size,
  retryCount,
  statusSummary,
  error: apiErrors.join(' | '),
  source: 'coupang_wing_openapi',
} }];

// CRM 직접거래: NocoDB에서 최근 명세표 조회 후 날짜 필터
const dateInfo = $('날짜 계산').first().json;
const token = $env.NOCODB_TOKEN || '';

if (!token) {
  return [{ json: { list: [], error: 'NOCODB_TOKEN 미설정' } }];
}

try {
  const data = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://nocodb.pressco21.com/api/v1/db/data/noco/pu0mwk97kac8a5p/ml81i9mcuw0pjzk',
    headers: { 'xc-token': token },
    qs: { sort: '-invoice_date', fields: 'Id,invoice_date,total_amount,payment_status', limit: 500 }
  });

  const allInvoices = data.list || [];
  const filtered = allInvoices.filter(inv => String(inv.invoice_date || '').startsWith(dateInfo.targetDate));

  return [{ json: { list: filtered, error: '' } }];
} catch (e) {
  return [{ json: { list: [], error: 'CRM: ' + e.message } }];
}

const dateInfo = $('날짜 계산').first().json;

const num = (v) => {
  if (v === undefined || v === null || v === '') return 0;
  return parseInt(String(v).replace(/[^0-9.-]/g, '')) || 0;
};

let existingRow = [];
try {
  const sheetResp = $('기존 시트 행 조회').first().json || {};
  existingRow = (sheetResp.values && sheetResp.values[0]) || [];
} catch(e) {}
const existingMakeShop = num(existingRow[0]);
const existingNaver = num(existingRow[1]);
const existingSt11 = num(existingRow[2]);
const existingCrm = num(existingRow[3]);
const existingCoupang = num(existingRow[4]); // C:J 조회 기준 G열

// 같은 날짜의 최신 daily_sales 레코드가 있으면, 쿠팡 API 오류/휴지시간 재실행 시 해당 값을 우선 보존한다.
let latestDailySales = null;
try {
  const token = String($env.NOCODB_TOKEN || '').trim();
  if (token) {
    const resp = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://nocodb.pressco21.com/api/v1/db/data/noco/pbmo0os7rnvfd48/mwxvxjiqtw177xu',
      headers: { 'xc-token': token },
      qs: {
        where: '(report_date,eq,' + dateInfo.targetDate + ')',
        sort: '-Id',
        limit: 5,
        fields: 'Id,report_date,coupang_revenue,coupang_orders,notes'
      }
    });
    for (const row of (resp.list || [])) {
      if (!latestDailySales || (parseInt(row.Id) || 0) > (parseInt(latestDailySales.Id) || 0)) latestDailySales = row;
    }
  }
} catch(e) {}
const latestDailySalesCoupang = latestDailySales ? num(latestDailySales.coupang_revenue) : 0;
const latestDailySalesCoupangOrders = latestDailySales ? num(latestDailySales.coupang_orders) : 0;
const hasStoredCoupangFallback = latestDailySalesCoupang > 0 || latestDailySalesCoupangOrders > 0;

const isPersonalPaymentOrder = (entry) => {
  const products = entry && entry.product ? entry.product : {};
  const list = Array.isArray(products) ? products : Object.values(products || {});
  const pattern = /개인\s*결제|개별\s*결제|개인\s*결재|개별\s*결재|개인결제|개별결제|개인결재|개별결재/i;
  for (const p of list) {
    const cate1 = String((p && p.product_cate1) || '');
    const brand = String((p && p.brandcode) || '');
    // PRESSCO21 개인결제 전용 카테고리: 097 / brandcode 097001...
    if (cate1 === '097' || brand.indexOf('097001') === 0) return true;
    const text = String((p && p.product_name) || '') + ' ' + String((p && p.option_data) || '') + ' ' + String((p && p.custom_option_data) || '');
    if (pattern.test(text)) return true;
  }
  return false;
};

const personalPaymentMatchText = (entry) => {
  const order = entry && entry.order ? entry.order : entry;
  const products = entry && entry.product ? entry.product : {};
  const list = Array.isArray(products) ? products : Object.values(products || {});
