    headers: { 'xc-token': token, 'Content-Type': 'application/json' },
    body: payload,
    timeout: 10000,
  });
  return [{ json: { ok: true, nocodb: { ok: true, action: 'post', id: created.Id || created.id || null, duplicateCount: 0, deletedDuplicateIds: [], duplicateDeleteErrors: [], reportDate: aggregate.reportDate }, payload } }];
} catch (e) {
  return [{ json: { ok: false, nocodb: { ok: false, action: 'error', error: e.message, reportDate: aggregate.reportDate }, payload } }];
}

const sheetItem = $('Sheets 저장 상태').first().json || {};
const saveItem = $('NocoDB 저장').first().json || {};
const aggregate = $('통합 집계').first().json || {};
const alerts = Array.isArray(sheetItem.opsAlerts) ? [...sheetItem.opsAlerts] : [];
const nocodb = saveItem.nocodb || {};

if (nocodb.ok === false) {
  alerts.push('<b>[운영알림][F23] NocoDB 저장 실패</b>\n'
    + '날짜: ' + (aggregate.reportDate || nocodb.reportDate || '') + '\n'
    + '조치: 구글시트 값은 기입됐을 수 있으나 원장 기준 F24/F26 리포트가 틀어질 수 있습니다.\n'
    + '오류: ' + String(nocodb.error || (nocodb.duplicateDeleteErrors || []).join(' | ') || 'unknown').slice(0, 700));
} else if ((nocodb.duplicateCount || 0) > 0) {
  alerts.push('<b>[운영알림][F23] NocoDB 중복 원장 자동 정리</b>\n'
    + '날짜: ' + (aggregate.reportDate || nocodb.reportDate || '') + '\n'
    + '유지 ID: ' + (nocodb.id || '') + '\n'
    + '삭제 ID: ' + (nocodb.deletedDuplicateIds || []).join(', '));
}

if (!alerts.length) return [];
return [{ json: {
  chatId: '-1003917399249',
  message: alerts.join('\n\n'),
  reportDate: aggregate.reportDate || nocodb.reportDate || '',
  alertCount: alerts.length,
} }];
